    ('criminal', 'probation', 'პრობაციის ბიუროს უფროსმა სამართლებრივი აქტის აღსრულება შემთხვევით შერჩეულ ოფიცერს გადასცა, მისამართისა და სამოქმედო ტერიტორიის გათვალისწინების გარეშე. უფლებამოსილმა პირმა საპირისპირო მოქმედება შეასრულა და საქმე სამართლებრივ შეფასებაზე გადავიდა. საქართველოს კანონი „დანაშაულის პრევენციის, არასაპატიმრო სასჯელთა აღსრულების წესისა და პრობაციის შესახებ“ შესაბამისად, რომელი პასუხი ასახავს სწორ სამართლებრივ შედეგს?', 'easy', 'სწორი პასუხია C, რადგან საქართველოს კანონი „დანაშაულის პრევენციის, არასაპატიმრო სასჯელთა აღსრულების წესისა და პრობაციის შესახებ“ მუხლი 16 ადგენს: ბიუროს უფროსი აქტს აღსასრულებლად გადასცემს პრობაციის ოფიცერს მსჯავრდებულის ფაქტობრივი ან იურიდიული მისამართისა და ბიუროს სამოქმედო ტერიტორიის მიხედვით.', 'საქართველოს კანონი „დანაშაულის პრევენციის, არასაპატიმრო სასჯელთა აღსრულების წესისა და პრობაციის შესახებ“', 'მუხლი 16', '', '2025-12-25', false, 'აქტი ნებისმიერ ოფიცერს გადაეცემა შემთხვევითობის პრინციპით.', 'აქტი ყოველთვის ბიუროს უფროსმა პირადად უნდა აღასრულოს.', 'ბიუროს უფროსი აქტს აღსასრულებლად გადასცემს პრობაციის ოფიცერს მსჯავრდებულის ფაქტობრივი ან იურიდიული მისამართისა და ბიუროს სამოქმედო ტერიტორიის მიხედვით.', 'აქტი მხოლოდ პროკურორს გადაეცემა.', 'C'),
    ('criminal', 'probation', 'პრობაციის ოფიცრის მიუკერძოებლობაზე ეჭვი წარმოიშვა, თუმცა ბიურომ განაცხადა, რომ თვითაცილება ან აცილება კანონით არ არის გათვალისწინებული. უფლებამოსილმა პირმა საპირისპირო მოქმედება შეასრულა და საქმე სამართლებრივ შეფასებაზე გადავიდა. საქართველოს კანონი „დანაშაულის პრევენციის, არასაპატიმრო სასჯელთა აღსრულების წესისა და პრობაციის შესახებ“ შესაბამისად, რომელი პასუხი ასახავს სწორ სამართლებრივ შედეგს?', 'medium', 'სწორი პასუხია D, რადგან საქართველოს კანონი „დანაშაულის პრევენციის, არასაპატიმრო სასჯელთა აღსრულების წესისა და პრობაციის შესახებ“ მუხლი 16¹ ადგენს: კანონი ითვალისწინებს პრობაციის ოფიცრის თვითაცილებისა და აცილების წესს.', 'საქართველოს კანონი „დანაშაულის პრევენციის, არასაპატიმრო სასჯელთა აღსრულების წესისა და პრობაციის შესახებ“', 'მუხლი 16¹', '', '2025-12-25', false, 'პრობაციის ოფიცრის აცილება შეუძლებელია ნებისმიერ შემთხვევაში.', 'აცილება მხოლოდ მოსამართლის მიმართ გამოიყენება.', 'აცილება მხოლოდ მსჯავრდებულის გარდაცვალების შემდეგ შეიძლება.', 'კანონი ითვალისწინებს პრობაციის ოფიცრის თვითაცილებისა და აცილების წესს.', 'D')
  ) as s(category_slug, subcategory_slug, text, difficulty, explanation, law_name, law_article, source_url, law_version_date, is_prime, option_a, option_b, option_c, option_d, correct_option)
  loop
    select id into v_article_id
    from public.law_articles
    where law_id = v_law_id and article_number = r.law_article;

    select id into v_question_id from public.questions
    where law_id = v_law_id and text = r.text limit 1;

    if v_question_id is null then
      insert into public.questions(category_id, subcategory_id, text, difficulty, explanation, law_name, law_article, source_url, law_version_date, needs_review, is_prime, is_published, verified_at, law_id, primary_law_article_id)
      values (v_category_id, v_subcategory_id, r.text, r.difficulty::public.difficulty, r.explanation, r.law_name, r.law_article, nullif(r.source_url,''), r.law_version_date::date, false, r.is_prime, true, now(), v_law_id, v_article_id)
      returning id into v_question_id;
    else
      update public.questions
      set category_id=v_category_id, subcategory_id=v_subcategory_id, difficulty=r.difficulty::public.difficulty,
          explanation=r.explanation, law_name=r.law_name, law_article=r.law_article,
          source_url=nullif(r.source_url,''), law_version_date=r.law_version_date::date,
          is_prime=r.is_prime, is_published=true, needs_review=false,
          primary_law_article_id=v_article_id, verified_at=coalesce(verified_at, now()), updated_at=now()
      where id=v_question_id;
    end if;

    insert into public.question_options(question_id, option_text, is_correct, sort_order) values
    (v_question_id, r.option_a, r.correct_option='A', 1),
    (v_question_id, r.option_b, r.correct_option='B', 2),
    (v_question_id, r.option_c, r.correct_option='C', 3),
    (v_question_id, r.option_d, r.correct_option='D', 4);

    insert into public.question_law_articles(question_id, law_article_id, is_primary)
    values (v_question_id, v_article_id, true)
    on conflict (question_id, law_article_id) do update set is_primary=true;
  end loop;
end $$;
